function PaymentConfirmation(a){var n=this,t=$("#"+a);this.tabID=a,this.updateOrderInformation=function(){var a=t.find("[name='hidSalesKey']").val();$.ajax({type:"GET",async:!1,url:"ajax-sales-order.php",data:"action=getDataRowById&pkey="+a+"&statuskey=1"}).done(function(a){a=(a=JSON.parse(a))[0],t.find("[name='customerName']").val(a.customername).blur(),t.find("[name='amount']").val(a.grandtotal).blur()})},this.rebindEl=function(){},this.loadOnReady=function(){n.rebindEl()}}